{
  std::lock_guard<std::mutex> lk(mtx_);
  x_ = msg->pose.pose.position.x;
  y_ = msg->pose.pose.position.y;
  yaw_ = yawFromQuat(msg->pose.pose.orientation);
  have_odom_ = true;
